INSERT INTO `management_instructions` (`id`, `instruction`, `created_at`, `updated_at`, `management_id`) VALUES
	(1, '1, இந்த பண்டில் வெளி நபர்கள் சேர்க்க அனுமதி இல்லை \n2, பண்டில்  கிடைக்கும் லாபத்தில் 10% கோவிலுக்கு கொடுக்க வேண்டும் \n3, மீதி லாபத்தை பங்கு வைத்துக் கொள்ளப்படும் \n4, ஒரு வருடத்திற்கு ஒரு முறை பங்கு பிரிக்கப்படும்\n5, செலவு மற்றும் நஷ்டங்களை லாபத்தில் கணக்கிடப்படும்\n6, ஞாயிற்றுக்கிழமை தோறும் 6 மணிக்குகூட்டம் நடைபெறும்\n7, பண்டில் உள்ளவர்கள் அனைவரும் கூட்டத்தில் தவறாமல் கலந்து கொள்ள வேண்டும் \n8, கூட்டத்தில் வந்து வரவு செலவு கணக்கு சரி பார்க்க வேண்டும்\n9,  இந்த பண்டில் இருந்து தினசரி வாரம் மாத வட்டிக்கு கொடுக்கப்படும்\n10, இந்த பண்டில் இருந்து இடை காலத்தில் முடித்தால் முடித்த தேதியிலிருந்து அறுபது நாட்கள் கழித்து பண்டு மற்றும் லாப பணத்தை  தரப்படும்', '2024-06-17 10:06:23.313595', '2025-02-26 07:22:08.687463', 1);
